noncompliant:
// C++14 attribute
[[deprecated]] // Noncompliant - should be removed
void oldFunction();

// GNU attribute
__attribute__((deprecated)) // Noncompliant - should be removed
void legacyFunction();

// Microsoft attribute
__declspec(deprecated) // Noncompliant - should be removed
void obsoleteFunction();

compliant:
// Compliant - deprecated code removed, only current implementation
void newFunction() {
  // Updated implementation
}

// Compliant - no deprecated attributes
void activeFunction() {
  // Current working code
}
